  ('police-94737317-moex-00071', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '關於憲法第22條規定，下列敘述何者正確？', '["本於一般行為自由得決定是否揭露個人資料", "隱私權僅指資訊隱私權", "資訊隱私權保障個人得向政府請求資訊公開", "保障一般行為自由的法理是人格自由發展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00072', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋意旨，立法者享有較大形成空間之基本權利，不包括下列何者？', '["公務人員依法銓敘取得官等俸給之服公職權", "人民於其權利受侵害時，得訴請救濟之訴訟權", "有關人民投票方法及程序之選舉權", "地方自治團體對於轄境內事務之自治權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00073', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依我國現行法制，下列何者為「不待許可，得隨時返回本國」之權利主體？', '["有中華民國國籍且在臺灣地區設有住所而有戶籍之人", "有中華民國國籍且在臺灣地區未設住所而無戶籍之人", "有中華人民共和國國籍且在臺灣地區未設住所而無戶籍之人", "有中華人民共和國國籍且在大陸地區設有住所而有戶籍之人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00074', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '下列何者並非限制結婚自由之規定？', '["司法院釋字第748號解釋施行法第2條規定：「相同性別之二人，得為經營共同生活之目的，成立具有 親密性及排他性之永久結合關係。」", "民法第985條第1項規定：「有配偶者，不得重婚。」", "民法第980條規定：「男女未滿18歲者，不得結婚。」", "民法第982條規定：「結婚應以書面為之，有2人以上證人之簽名，並應由雙方當事人向戶政機關為結 婚之登記。」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00075', 'police-94737317', 'police-94737317-moex-113-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '關於行政院覆議案，下列敘述何者正確？', '["覆議對象為立法院議決之法律案、預算案之全部或一部，以及移請變更重要政策之決議", "行政院移請立法院覆議前，須經總統核可，並應於立法院決議案送達行政院15日內為之", "立法院休會期間行政院移請覆議時，立法院院長應召開臨時會，並於開議7日內作成決議", "覆議時，贊成維持原決議者如未達全體立法委員二分之一，原決議即不予維持"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "8b6a7038f54c", "answer_pdf_sha1": "14a3dd2355dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL)
